import type { TLShapeId } from "tldraw"
import { describe, expect, it } from "vitest"
import {
  type PinSnapshot,
  type ShapeSnapshot,
  computePinUpdates,
} from "./use-pin-attachment"

const id = (s: string) => `shape:${s}` as TLShapeId

const xy = (shape: ShapeSnapshot | undefined) =>
  shape ? { x: shape.x, y: shape.y } : undefined

function makeLookup(shapes: ShapeSnapshot[]) {
  const map = new Map(shapes.map((s) => [s.id, s]))
  return (lookupId: TLShapeId) => map.get(lookupId) ?? null
}

describe("computePinUpdates", () => {
  it("moves the pin and the other attached shape when a 2-shape set moves", () => {
    const shapeA: ShapeSnapshot = { id: id("a"), type: "geo", x: 10, y: 10 }
    const shapeB: ShapeSnapshot = { id: id("b"), type: "geo", x: 50, y: 50 }
    const pin: PinSnapshot = {
      id: id("pin1"),
      x: 5,
      y: 5,
      attachedShapeIds: [shapeA.id, shapeB.id],
    }

    const updates = computePinUpdates(
      [pin],
      shapeA.id,
      10,
      -5,
      makeLookup([shapeA, shapeB])
    )

    expect(updates).toHaveLength(2)
    expect(xy(updates.find((u) => u.id === pin.id))).toEqual({ x: 15, y: 0 })
    expect(xy(updates.find((u) => u.id === shapeB.id))).toEqual({
      x: 60,
      y: 45,
    })
    // The moved shape itself should not be in the update list — the caller has
    // already applied that move.
    expect(updates.find((u) => u.id === shapeA.id)).toBeUndefined()
  })

  it("moves every other member of a 3-shape set", () => {
    const shapes: ShapeSnapshot[] = [
      { id: id("a"), type: "geo", x: 0, y: 0 },
      { id: id("b"), type: "geo", x: 20, y: 20 },
      { id: id("c"), type: "image", x: 40, y: 40 },
    ]
    const pin: PinSnapshot = {
      id: id("pin1"),
      x: 0,
      y: 0,
      attachedShapeIds: shapes.map((s) => s.id),
    }

    const updates = computePinUpdates([pin], id("b"), 5, 7, makeLookup(shapes))

    expect(updates).toHaveLength(3)
    expect(xy(updates.find((u) => u.id === pin.id))).toEqual({ x: 5, y: 7 })
    expect(xy(updates.find((u) => u.id === id("a")))).toEqual({ x: 5, y: 7 })
    expect(xy(updates.find((u) => u.id === id("c")))).toEqual({ x: 45, y: 47 })
    // shape B is the mover and must not appear in the update list.
    expect(updates.find((u) => u.id === id("b"))).toBeUndefined()

    // Preserve each shape's own type so the caller can round-trip the patch.
    expect(updates.find((u) => u.id === id("c"))?.type).toBe("image")
  })

  it("propagates across overlapping sets without duplicating updates", () => {
    // A = {X, Y}, B = {Y, Z}. Moving Y must move X, Z and both pins — each
    // shape once, even though Y appears in both sets.
    const x: ShapeSnapshot = { id: id("x"), type: "geo", x: 100, y: 100 }
    const y: ShapeSnapshot = { id: id("y"), type: "geo", x: 200, y: 200 }
    const z: ShapeSnapshot = { id: id("z"), type: "geo", x: 300, y: 300 }

    const pinA: PinSnapshot = {
      id: id("pinA"),
      x: 0,
      y: 0,
      attachedShapeIds: [x.id, y.id],
    }
    const pinB: PinSnapshot = {
      id: id("pinB"),
      x: 1,
      y: 1,
      attachedShapeIds: [y.id, z.id],
    }

    const updates = computePinUpdates(
      [pinA, pinB],
      y.id,
      10,
      10,
      makeLookup([x, y, z])
    )

    const ids = updates.map((u) => u.id)
    // Four distinct targets: two pins plus X and Z. No duplicates, no Y.
    expect(ids).toHaveLength(4)
    expect(new Set(ids).size).toBe(4)
    expect(ids).toContain(pinA.id)
    expect(ids).toContain(pinB.id)
    expect(ids).toContain(x.id)
    expect(ids).toContain(z.id)
    expect(ids).not.toContain(y.id)

    expect(xy(updates.find((u) => u.id === x.id))).toEqual({ x: 110, y: 110 })
    expect(xy(updates.find((u) => u.id === z.id))).toEqual({ x: 310, y: 310 })
  })

  it("returns nothing for a 1-shape attached set (no grouping effect)", () => {
    const shape: ShapeSnapshot = { id: id("a"), type: "geo", x: 0, y: 0 }
    const pin: PinSnapshot = {
      id: id("pin1"),
      x: 0,
      y: 0,
      attachedShapeIds: [shape.id],
    }

    const updates = computePinUpdates(
      [pin],
      shape.id,
      10,
      10,
      makeLookup([shape])
    )

    // Ticket decision: a pin over one (or zero) shape still exists but does
    // not group-move. The pin itself still follows, so we expect just the pin.
    expect(updates).toHaveLength(1)
    expect(updates[0]?.id).toBe(pin.id)
  })

  it("skips attached ids whose shapes no longer exist (stale ids)", () => {
    // After a delete the side-effect prunes the id from each pin's set, but
    // that pruning happens in the afterDelete handler — another afterChange
    // handler running in the same tick could still see a stale id. The pure
    // helper must skip those instead of emitting undefined moves.
    const live: ShapeSnapshot = { id: id("live"), type: "geo", x: 0, y: 0 }
    const moved: ShapeSnapshot = { id: id("moved"), type: "geo", x: 0, y: 0 }
    const pin: PinSnapshot = {
      id: id("pin1"),
      x: 0,
      y: 0,
      attachedShapeIds: [moved.id, live.id, id("gone")],
    }

    const updates = computePinUpdates(
      [pin],
      moved.id,
      3,
      4,
      makeLookup([moved, live])
    )

    // Pin + live shape only — the "gone" id is silently skipped.
    expect(updates).toHaveLength(2)
    expect(updates.find((u) => u.id === id("gone"))).toBeUndefined()
    expect(xy(updates.find((u) => u.id === live.id))).toEqual({ x: 3, y: 4 })
  })

  it("ignores pins whose attached set does not contain the moved shape", () => {
    const shape: ShapeSnapshot = { id: id("a"), type: "geo", x: 0, y: 0 }
    const other: ShapeSnapshot = { id: id("b"), type: "geo", x: 0, y: 0 }
    const unrelated: PinSnapshot = {
      id: id("pin1"),
      x: 0,
      y: 0,
      attachedShapeIds: [id("c"), id("d")],
    }

    const updates = computePinUpdates(
      [unrelated],
      shape.id,
      5,
      5,
      makeLookup([shape, other])
    )

    expect(updates).toEqual([])
  })
})

import type { PDFDocumentProxy } from "pdfjs-dist"

// Dynamic import keeps pdfjs-dist out of the SSR bundle — it accesses DOMMatrix
// and other browser globals at module evaluation time, crashing Next.js builds.
async function pdfjs() {
  return import("pdfjs-dist")
}

let workerSet = false

async function ensureWorker() {
  if (workerSet) return
  const { GlobalWorkerOptions } = await pdfjs()
  GlobalWorkerOptions.workerSrc = "/pdf.worker.min.mjs"
  workerSet = true
}

export interface PageDimensions {
  w: number
  h: number
  x: number
  y: number
}

const GUTTER = 20

export async function openPdf(bytes: Uint8Array): Promise<PDFDocumentProxy> {
  await ensureWorker()
  const { getDocument } = await pdfjs()
  return getDocument({ data: bytes }).promise
}

export async function getPageLayout(
  pdf: PDFDocumentProxy
): Promise<PageDimensions[]> {
  const pages = await Promise.all(
    Array.from({ length: pdf.numPages }, (_, i) => pdf.getPage(i + 1))
  )

  const layout: PageDimensions[] = []
  let yOffset = 0

  for (const page of pages) {
    const vp = page.getViewport({ scale: 1 })
    layout.push({ w: vp.width, h: vp.height, x: -vp.width / 2, y: yOffset })
    yOffset += vp.height + GUTTER
  }

  return layout
}

export async function renderPage(
  pdf: PDFDocumentProxy,
  pageNumber: number,
  { dprCap = 3 }: { dprCap?: number } = {}
): Promise<Blob> {
  const scale = Math.min(devicePixelRatio * 2, dprCap)
  const page = await pdf.getPage(pageNumber)
  const viewport = page.getViewport({ scale })
  const canvas = new OffscreenCanvas(
    Math.round(viewport.width),
    Math.round(viewport.height)
  )
  const ctx = canvas.getContext("2d")
  if (!ctx) throw new Error("OffscreenCanvas 2d context unavailable")
  // pdfjs types require HTMLCanvasElement but accepts OffscreenCanvas at runtime
  await page.render({
    canvasContext: ctx as unknown as CanvasRenderingContext2D,
    canvas: canvas as unknown as HTMLCanvasElement,
    viewport,
  }).promise
  return canvas.convertToBlob({ type: "image/png" })
}

"use client"

import { useEffect } from "react"
import type { Editor, TLShape, TLShapeId } from "tldraw"
import type { TLPinShape } from "./pin-shape-util"

export interface PinSnapshot {
  id: TLShapeId
  x: number
  y: number
  attachedShapeIds: readonly TLShapeId[]
}

export interface ShapeSnapshot {
  id: TLShapeId
  type: TLShape["type"]
  x: number
  y: number
}

export type ShapeMove = ShapeSnapshot

// Module-level propagation guard. Lives outside React so it survives hook
// remounts and stays shared across any concurrent handler invocations inside
// a single editor batch.
let isPropagating = false

// Pure helper so we can unit-test the delta math without mounting tldraw.
// Returns the list of shape/pin moves triggered by `movedShapeId` shifting by
// (dx, dy). The moved shape itself is not included — the caller has already
// applied that move. Each affected shape (and pin) is emitted once, even when
// several pins' attached sets overlap.
export function computePinUpdates(
  pins: readonly PinSnapshot[],
  movedShapeId: TLShapeId,
  dx: number,
  dy: number,
  getShape: (id: TLShapeId) => ShapeSnapshot | null
): ShapeMove[] {
  const updates: ShapeMove[] = []
  const seen = new Set<TLShapeId>([movedShapeId])

  for (const pin of pins) {
    if (!pin.attachedShapeIds.includes(movedShapeId)) continue

    if (!seen.has(pin.id)) {
      seen.add(pin.id)
      updates.push({
        id: pin.id,
        type: "pin",
        x: pin.x + dx,
        y: pin.y + dy,
      })
    }

    for (const shapeId of pin.attachedShapeIds) {
      if (seen.has(shapeId)) continue
      const shape = getShape(shapeId)
      if (!shape) continue
      seen.add(shapeId)
      updates.push({
        id: shapeId,
        type: shape.type,
        x: shape.x + dx,
        y: shape.y + dy,
      })
    }
  }

  return updates
}

function snapshotPins(editor: Editor): PinSnapshot[] {
  const result: PinSnapshot[] = []
  for (const shape of editor.getCurrentPageShapes()) {
    if (shape.type !== "pin") continue
    const pin = shape as TLPinShape
    result.push({
      id: pin.id,
      x: pin.x,
      y: pin.y,
      attachedShapeIds: pin.props.attachedShapeIds,
    })
  }
  return result
}

export function usePinAttachment(editor: Editor | null) {
  useEffect(() => {
    if (!editor) return

    const disposeChange = editor.sideEffects.registerAfterChangeHandler(
      "shape",
      (prev, next) => {
        if (isPropagating) return
        if (next.type === "pin") return
        if (next.x === prev.x && next.y === prev.y) return

        const pins = snapshotPins(editor)
        if (pins.length === 0) return

        const dx = next.x - prev.x
        const dy = next.y - prev.y

        const updates = computePinUpdates(pins, next.id, dx, dy, (id) => {
          const shape = editor.getShape(id)
          if (!shape) return null
          return { id: shape.id, type: shape.type, x: shape.x, y: shape.y }
        })

        if (updates.length === 0) return

        isPropagating = true
        try {
          editor.run(() => {
            editor.updateShapes(
              updates.map((u) => ({
                id: u.id,
                type: u.type,
                x: u.x,
                y: u.y,
              }))
            )
          })
        } finally {
          isPropagating = false
        }
      }
    )

    const disposeDelete = editor.sideEffects.registerAfterDeleteHandler(
      "shape",
      (deleted: TLShape) => {
        if (deleted.type === "pin") return

        const pins = snapshotPins(editor).filter((pin) =>
          pin.attachedShapeIds.includes(deleted.id)
        )
        if (pins.length === 0) return

        editor.run(() => {
          const pinsToDelete: TLShapeId[] = []
          const pinsToUpdate: Array<{
            id: TLShapeId
            type: "pin"
            props: { attachedShapeIds: TLShapeId[] }
          }> = []

          for (const pin of pins) {
            const nextIds = pin.attachedShapeIds.filter(
              (id) => id !== deleted.id
            )
            if (nextIds.length < 2) {
              pinsToDelete.push(pin.id)
            } else {
              pinsToUpdate.push({
                id: pin.id,
                type: "pin",
                props: { attachedShapeIds: nextIds },
              })
            }
          }

          if (pinsToUpdate.length > 0) {
            editor.updateShapes(pinsToUpdate)
          }
          if (pinsToDelete.length > 0) {
            editor.deleteShapes(pinsToDelete)
          }
        })
      }
    )

    return () => {
      disposeChange()
      disposeDelete()
    }
  }, [editor])
}

