"use client"

import { Skeleton } from "@/components/ui/skeleton"
import { useState } from "react"
import { CameraButton } from "./camera-button"
import Canvas from "./editor"
import { ExportButton } from "./export-button"
import { PdfLoader } from "./pdf-loader"
import { PdfShapes } from "./pdf-shapes"

type CanvasState =
  | { status: "empty" }
  | { status: "loading" }
  | { status: "loaded"; bytes: Uint8Array }
  | { status: "error"; message: string }

export function CanvasHost() {
  const [state, setState] = useState<CanvasState>({ status: "empty" })

  function handleFile(bytes: Uint8Array) {
    setState({ status: "loaded", bytes })
  }

  async function handleExample() {
    setState({ status: "loading" })
    try {
      const res = await fetch("/sample.pdf")
      if (!res.ok) throw new Error(`fetch failed: ${res.status}`)
      const buf = await res.arrayBuffer()
      setState({ status: "loaded", bytes: new Uint8Array(buf) })
    } catch (err) {
      setState({
        status: "error",
        message: err instanceof Error ? err.message : "Failed to load sample.",
      })
    }
  }

  function handleError(message: string) {
    setState({ status: "error", message })
  }

  if (state.status === "empty" || state.status === "error") {
    return (
      <PdfLoader
        onFile={handleFile}
        onExample={handleExample}
        onError={handleError}
        error={state.status === "error" ? state.message : undefined}
      />
    )
  }

  if (state.status === "loading") {
    return (
      <div className="flex min-h-svh items-center justify-center">
        <div className="flex w-full max-w-sm flex-col gap-3 p-8">
          <Skeleton className="h-6 w-3/4" />
          <Skeleton className="h-4 w-full" />
          <Skeleton className="h-4 w-5/6" />
          <Skeleton className="mt-4 h-64 w-full rounded-xl" />
        </div>
      </div>
    )
  }

  return (
    <Canvas>
      <PdfShapes bytes={state.bytes} onError={handleError} />
      <div className="pointer-events-none fixed inset-0 z-10">
        <div className="pointer-events-auto absolute right-4 top-4 flex gap-2">
          <CameraButton />
          <ExportButton bytes={state.bytes} />
        </div>
      </div>
    </Canvas>
  )
}

"use client"

import { Button } from "@/components/ui/button"
import { useRef } from "react"

interface PdfLoaderProps {
  onFile: (bytes: Uint8Array) => void
  onExample: () => void
  onError: (message: string) => void
  error?: string
}

export function PdfLoader({
  onFile,
  onExample,
  onError,
  error,
}: PdfLoaderProps) {
  const inputRef = useRef<HTMLInputElement>(null)

  async function handleFileChange(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0]
    if (!file) return
    e.target.value = ""
    try {
      const buf = await file.arrayBuffer()
      onFile(new Uint8Array(buf))
    } catch (err) {
      onError(err instanceof Error ? err.message : "Failed to read file.")
    }
  }

  return (
    <div className="flex min-h-svh items-center justify-center">
      <div className="flex w-full max-w-sm flex-col gap-4 rounded-xl border border-border bg-card p-8 shadow-sm">
        <div className="space-y-1">
          <h2 className="text-lg font-semibold">Open a PDF</h2>
          <p className="text-sm text-muted-foreground">
            Load a file from your device or try a sample.
          </p>
        </div>
        {error && <p className="text-sm text-destructive">{error}</p>}
        <div className="flex flex-col gap-2">
          <Button onClick={() => inputRef.current?.click()}>Open PDF</Button>
          <Button variant="outline" onClick={onExample}>
            Use an example
          </Button>
        </div>
        <input
          ref={inputRef}
          type="file"
          accept="application/pdf"
          className="hidden"
          onChange={handleFileChange}
        />
      </div>
    </div>
  )
}

"use client"

import { CameraTool } from "@/tools/camera/camera-tool"
import { CropOverlay } from "@/tools/camera/crop-overlay"
import { PinShapeUtil } from "@/tools/pin/pin-shape-util"
import { PinTool } from "@/tools/pin/pin-tool"
import { usePinAttachment } from "@/tools/pin/use-pin-attachment"
import { createContext, useContext, useState } from "react"
import {
  DefaultToolbar,
  DefaultToolbarContent,
  type Editor,
  type TLComponents,
  type TLUiAssetUrlOverrides,
  type TLUiOverrides,
  Tldraw,
  TldrawUiMenuItem,
  useIsToolSelected,
  useTools,
} from "tldraw"

const EditorContext = createContext<Editor | null>(null)

export function useEditor(): Editor | null {
  return useContext(EditorContext)
}

const customShapeUtils = [PinShapeUtil]
const customTools = [PinTool, CameraTool]

const PIN_ICON_ID = "pin-tool-icon"

// Inline SVG of the lucide `MapPin` icon (lucide-react v1.8.0, see
// node_modules/lucide-react/dist/esm/icons/map-pin.js), served as a data URL
// through tldraw's `assetUrls.icons` pipeline. tldraw renders toolbar icons as
// CSS masks, so the icon must come in as a single URL — rendering `<MapPin />`
// as JSX would bypass that and lose the active-tool highlight styling. When
// lucide publishes an updated MapPin, refresh the path data below.
const assetUrls: TLUiAssetUrlOverrides = {
  icons: {
    [PIN_ICON_ID]: `data:image/svg+xml;utf8,${encodeURIComponent(
      '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M20 10c0 4.993-5.539 10.193-7.399 11.799a1 1 0 0 1-1.202 0C9.539 20.193 4 14.993 4 10a8 8 0 0 1 16 0"/><circle cx="12" cy="10" r="3"/></svg>'
    )}`,
  },
}

const uiOverrides: TLUiOverrides = {
  tools(editor, tools) {
    tools.pin = {
      id: "pin",
      label: "Pin",
      icon: PIN_ICON_ID,
      kbd: "p",
      onSelect: () => editor.setCurrentTool("pin"),
    }
    return tools
  },
}

function PinToolbarItem() {
  const tools = useTools()
  const pin = tools.pin
  const isSelected = useIsToolSelected(pin)
  if (!pin) return null
  return <TldrawUiMenuItem {...pin} isSelected={isSelected} />
}

const components: TLComponents = {
  InFrontOfTheCanvas: CropOverlay,
  Toolbar() {
    return (
      <DefaultToolbar>
        <PinToolbarItem />
        <DefaultToolbarContent />
      </DefaultToolbar>
    )
  },
}

function AttachmentBridge() {
  const editor = useEditor()
  usePinAttachment(editor)
  return null
}

export default function Canvas({
  children,
}: {
  children?: React.ReactNode
}) {
  const [editor, setEditor] = useState<Editor | null>(null)

  return (
    <EditorContext.Provider value={editor}>
      <div className="fixed inset-0">
        <Tldraw
          onMount={setEditor}
          shapeUtils={customShapeUtils}
          tools={customTools}
          overrides={uiOverrides}
          components={components}
          assetUrls={assetUrls}
        />
      </div>
      <AttachmentBridge />
      {children}
    </EditorContext.Provider>
  )
}

import { Box, StateNode, atom } from "tldraw"
import type { TLKeyboardEventInfo, TLPointerEventInfo } from "tldraw"
import { exportCropImage } from "./export-image"

type CropState =
  | { status: "idle" }
  | {
      status: "dragging"
      startX: number
      startY: number
      currentX: number
      currentY: number
    }

export const cropStateAtom = atom<CropState>("camera/cropState", {
  status: "idle",
})

export class CameraTool extends StateNode {
  static override id = "camera"

  override onEnter() {
    this.editor.setCursor({ type: "cross", rotation: 0 })
  }

  override onExit() {
    cropStateAtom.set({ status: "idle" })
    this.editor.setCursor({ type: "default", rotation: 0 })
  }

  override onPointerDown(_info: TLPointerEventInfo) {
    const { x, y } = this.editor.inputs.currentPagePoint
    cropStateAtom.set({
      status: "dragging",
      startX: x,
      startY: y,
      currentX: x,
      currentY: y,
    })
  }

  override onPointerMove(_info: TLPointerEventInfo) {
    const state = cropStateAtom.get()
    if (state.status !== "dragging") return
    const { x, y } = this.editor.inputs.currentPagePoint
    cropStateAtom.set({ ...state, currentX: x, currentY: y })
  }

  override onPointerUp(_info: TLPointerEventInfo) {
    const state = cropStateAtom.get()
    if (state.status !== "dragging") return

    const { startX, startY, currentX, currentY } = state
    cropStateAtom.set({ status: "idle" })

    const w = Math.abs(currentX - startX)
    const h = Math.abs(currentY - startY)

    if (w > 8 && h > 8) {
      const bounds = Box.FromPoints([
        { x: startX, y: startY },
        { x: currentX, y: currentY },
      ])
      exportCropImage(this.editor, bounds)
    }

    this.editor.setCurrentTool("select")
  }

  override onKeyDown(info: TLKeyboardEventInfo) {
    if (info.key === "Escape") {
      cropStateAtom.set({ status: "idle" })
      this.editor.setCurrentTool("select")
    }
  }
}

"use client"

import { useEditor, useValue } from "tldraw"
import { cropStateAtom } from "./camera-tool"

export function CropOverlay() {
  const editor = useEditor()

  const rect = useValue(
    "cropRect",
    () => {
      const state = cropStateAtom.get()
      if (state.status !== "dragging") return null
      const s = editor.pageToScreen({ x: state.startX, y: state.startY })
      const e = editor.pageToScreen({ x: state.currentX, y: state.currentY })
      return {
        x: Math.min(s.x, e.x),
        y: Math.min(s.y, e.y),
        w: Math.abs(e.x - s.x),
        h: Math.abs(e.y - s.y),
      }
    },
    [editor]
  )

  if (!rect) return null

  return (
    <svg
      aria-hidden="true"
      style={{
        position: "absolute",
        inset: 0,
        width: "100%",
        height: "100%",
        pointerEvents: "none",
        overflow: "visible",
      }}
    >
      {/* shadow stroke for contrast */}
      <rect
        x={rect.x}
        y={rect.y}
        width={rect.w}
        height={rect.h}
        fill="rgba(0,0,0,0.1)"
        stroke="rgba(0,0,0,0.5)"
        strokeWidth={3}
        strokeDasharray="8 4"
      />
      {/* white marching-ants stroke — animation defined in globals.css */}
      <rect
        className="tl-camera-marquee"
        x={rect.x}
        y={rect.y}
        width={rect.w}
        height={rect.h}
        fill="none"
        stroke="white"
        strokeWidth={1.5}
        strokeDasharray="8 4"
      />
    </svg>
  )
}

"use client"

import { Button } from "@/components/ui/button"
import { Camera } from "lucide-react"
import { useEditor } from "./editor"

export function CameraButton() {
  const editor = useEditor()
  if (!editor) return null

  return (
    <Button
      variant="outline"
      size="icon"
      onClick={() => editor.setCurrentTool("camera")}
      aria-label="Camera tool: drag to crop and export"
    >
      <Camera className="h-4 w-4" />
    </Button>
  )
}

import { toast } from "sonner"
import type { Box, Editor } from "tldraw"

export async function exportCropImage(editor: Editor, bounds: Box) {
  const filename = "screenshot.png"
  try {
    const shapeIds = [...editor.getShapeIdsInsideBounds(bounds)]
    const { blob } = await editor.toImage(shapeIds, {
      bounds,
      format: "png",
      background: true,
      pixelRatio: window.devicePixelRatio,
      padding: 0,
    })
    downloadBlob(blob, filename)
    toast.success(`Exported ${filename}`)
  } catch (err) {
    console.error(
      "[camera] toImage failed, falling back to html-to-image:",
      err
    )
    await fallbackExport(editor, filename)
  }
}

// Fallback: captures the full canvas container (no cropping).
// Used when toImage() throws (e.g. missing WebGL context in some environments).
async function fallbackExport(editor: Editor, filename: string) {
  try {
    const { toPng } = await import("html-to-image")
    const container = editor.getContainer()
    const dataUrl = await toPng(container)
    const a = document.createElement("a")
    a.href = dataUrl
    a.download = filename
    document.body.appendChild(a)
    a.click()
    document.body.removeChild(a)
    toast.success(`Exported ${filename} (full canvas — crop unavailable)`)
  } catch (err) {
    console.error("[camera] fallback export failed:", err)
    toast.error("Export failed")
  }
}

function downloadBlob(blob: Blob, filename: string) {
  const url = URL.createObjectURL(blob)
  const a = document.createElement("a")
  a.href = url
  a.download = filename
  document.body.appendChild(a)
  a.click()
  document.body.removeChild(a)
  setTimeout(() => URL.revokeObjectURL(url), 100)
}

