test("camera marquee triggers PNG download", async ({ page }) => {
  await page.goto("/")

  await expect(page.locator(".tl-canvas")).toBeVisible({ timeout: 15_000 })

  // Wait for the dev-mode editor hook
  await page.waitForFunction(() => !!(window as { __editor?: unknown }).__editor, {
