import { expect, test } from "@playwright/test"

test("Use an example mounts canvas with PDF page shapes", async ({ page }) => {
  await page.goto("/")
  await page.getByRole("button", { name: "Use an example" }).click()

  // Wait for the editor to mount AND for at least one PDF page shape to appear
  await page.waitForFunction(
    () => {
      // biome-ignore lint/suspicious/noExplicitAny: test-only tldraw editor hook
      const e = (window as { __editor?: any }).__editor
      if (!e) return false
      return e.getCurrentPageShapes().length > 0
    },
    { timeout: 25_000 }
  )

  const count = await page.evaluate(() => {
    // biome-ignore lint/suspicious/noExplicitAny: test-only tldraw editor hook
    const e = (window as { __editor?: any }).__editor
    return e.getCurrentPageShapes().length
  })
  expect(count).toBeGreaterThan(0)
})

import { expect, test } from "@playwright/test"

test("pin and attached shapes translate by the same delta", async ({
  page,
}) => {
  await page.goto("/")

  // Load example PDF so tldraw canvas mounts
  await page.getByRole("button", { name: "Use an example" }).click()

  // Wait for the dev-mode editor hook to be set
  await page.waitForFunction(
    () => !!(window as { __editor?: unknown }).__editor,
    { timeout: 20_000 }
  )

  // Create two overlapping geo shapes and a pin attached to both
  const ids = await page.evaluate(() => {
    // biome-ignore lint/suspicious/noExplicitAny: test-only tldraw editor hook
    const e = (window as { __editor?: any }).__editor
    const ts = Date.now()
    const idA = `shape:pe-a-${ts}`
    const idB = `shape:pe-b-${ts}`
    const idPin = `shape:pe-pin-${ts}`

    e.createShapes([
      { id: idA, type: "geo", x: 100, y: 100, props: { w: 200, h: 200 } },
      { id: idB, type: "geo", x: 150, y: 150, props: { w: 200, h: 200 } },
    ])
    e.createShape({
      id: idPin,
      type: "pin",
      x: 160,
      y: 148,
      props: { attachedShapeIds: [idA, idB] },
    })

    return { idA, idB, idPin }
  })

  // Move shape A by dx=50, dy=30.
  // Wrapped in editor.run() to match tldraw's normal pointer-event batch context —
  // calling updateShape bare triggers flushAtomicCallbacks re-entrancy.
  await page.evaluate(({ idA }) => {
    // biome-ignore lint/suspicious/noExplicitAny: test-only tldraw editor hook
    const e = (window as { __editor?: any }).__editor
    const shape = e.getShape(idA)
    e.run(() => {
      e.updateShape({ id: idA, type: "geo", x: shape.x + 50, y: shape.y + 30 })
    })
  }, ids)

  // Give React / tldraw side-effects a tick to settle
  await page.waitForTimeout(100)

  const result = await page.evaluate(({ idA, idB, idPin }) => {
    // biome-ignore lint/suspicious/noExplicitAny: test-only tldraw editor hook
    const e = (window as { __editor?: any }).__editor
    return {
      a: { x: e.getShape(idA).x, y: e.getShape(idA).y },
      b: { x: e.getShape(idB).x, y: e.getShape(idB).y },
      pin: { x: e.getShape(idPin).x, y: e.getShape(idPin).y },
    }
  }, ids)

  // A moved by (+50, +30) → B and pin must carry the same delta
  expect(result.a.x - 100).toBe(50)
  expect(result.a.y - 100).toBe(30)
  expect(result.b.x - 150).toBe(50)
  expect(result.b.y - 150).toBe(30)
  expect(result.pin.x - 160).toBe(50)
  expect(result.pin.y - 148).toBe(30)
})

"use client"

import { CameraTool } from "@/tools/camera/camera-tool"
import { CropOverlay } from "@/tools/camera/crop-overlay"
import { PinShapeUtil } from "@/tools/pin/pin-shape-util"
import { PinTool } from "@/tools/pin/pin-tool"
import { usePinAttachment } from "@/tools/pin/use-pin-attachment"
import { createContext, useContext, useState } from "react"
import {
  DefaultToolbar,
  DefaultToolbarContent,
  type Editor,
  type TLComponents,
  type TLUiAssetUrlOverrides,
  type TLUiOverrides,
  Tldraw,
  TldrawUiMenuItem,
  useIsToolSelected,
  useTools,
} from "tldraw"

const EditorContext = createContext<Editor | null>(null)

export function useEditor(): Editor | null {
  return useContext(EditorContext)
}

const customShapeUtils = [PinShapeUtil]
const customTools = [PinTool, CameraTool]

const PIN_ICON_ID = "pin-tool-icon"

// Inline SVG of the lucide `MapPin` icon (lucide-react v1.8.0, see
// node_modules/lucide-react/dist/esm/icons/map-pin.js), served as a data URL
// through tldraw's `assetUrls.icons` pipeline. tldraw renders toolbar icons as
// CSS masks, so the icon must come in as a single URL — rendering `<MapPin />`
// as JSX would bypass that and lose the active-tool highlight styling. When
// lucide publishes an updated MapPin, refresh the path data below.
const assetUrls: TLUiAssetUrlOverrides = {
  icons: {
    [PIN_ICON_ID]: `data:image/svg+xml;utf8,${encodeURIComponent(
      '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M20 10c0 4.993-5.539 10.193-7.399 11.799a1 1 0 0 1-1.202 0C9.539 20.193 4 14.993 4 10a8 8 0 0 1 16 0"/><circle cx="12" cy="10" r="3"/></svg>'
    )}`,
  },
}

const uiOverrides: TLUiOverrides = {
  tools(editor, tools) {
    tools.pin = {
      id: "pin",
      label: "Pin",
      icon: PIN_ICON_ID,
      kbd: "p",
      onSelect: () => editor.setCurrentTool("pin"),
    }
    return tools
  },
}

function PinToolbarItem() {
  const tools = useTools()
  const pin = tools.pin
  const isSelected = useIsToolSelected(pin)
  if (!pin) return null
  return <TldrawUiMenuItem {...pin} isSelected={isSelected} />
}

const components: TLComponents = {
  InFrontOfTheCanvas: CropOverlay,
  Toolbar() {
    return (
      <DefaultToolbar>
        <PinToolbarItem />
        <DefaultToolbarContent />
      </DefaultToolbar>
    )
  },
}

function AttachmentBridge() {
  const editor = useEditor()
  usePinAttachment(editor)
  return null
}

export default function Canvas({
  children,
}: {
  children?: React.ReactNode
}) {
  const [editor, setEditor] = useState<Editor | null>(null)

  function handleMount(e: Editor) {
    setEditor(e)
    // Test hook — lets E2E specs call editor APIs via window.__editor
    // @ts-expect-error test-only
    window.__editor = e
  }

  return (
    <EditorContext.Provider value={editor}>
      <div className="fixed inset-0">
        <Tldraw
          onMount={handleMount}
          shapeUtils={customShapeUtils}
          tools={customTools}
          overrides={uiOverrides}
          components={components}
          assetUrls={assetUrls}
        />
      </div>
      <AttachmentBridge />
      {children}
    </EditorContext.Provider>
  )
}

import { expect, test } from "@playwright/test"

test("camera marquee triggers PNG download", async ({ page }) => {
  await page.goto("/")

  // Load example PDF so tldraw canvas mounts
  await page.getByRole("button", { name: "Use an example" }).click()
  await expect(page.locator(".tl-canvas")).toBeVisible({ timeout: 20_000 })

  // Wait for the dev-mode editor hook
  await page.waitForFunction(
    () => !!(window as { __editor?: unknown }).__editor,
    { timeout: 15_000 }
  )

  // Zoom to fit so that canvas content is visible in the viewport
  await page.evaluate(() => {
    // biome-ignore lint/suspicious/noExplicitAny: test-only tldraw editor hook
    const e = (window as { __editor?: any }).__editor
    e.zoomToFit({ animation: { duration: 0 } })
  })

  await page.waitForTimeout(100)

  // Activate camera tool via the toolbar button
  await page
    .getByRole("button", { name: "Camera tool: drag to crop and export" })
    .click()

  const viewport = page.viewportSize() ?? { width: 1280, height: 720 }
  const cx = viewport.width / 2
  const cy = viewport.height / 2

  // Arm the download listener before the action that triggers it
  const downloadPromise = page.waitForEvent("download", { timeout: 20_000 })

  // Draw a 160×120 px marquee centred in the viewport
  await page.mouse.move(cx - 80, cy - 60)
  await page.mouse.down()
  await page.mouse.move(cx + 80, cy + 60, { steps: 10 })
  await page.mouse.up()

  const download = await downloadPromise
  expect(download.suggestedFilename()).toBe("screenshot.png")
})

"use client"

import { useEffect } from "react"
import type { Editor, TLShape, TLShapeId } from "tldraw"
import type { TLPinShape } from "./pin-shape-util"

export interface PinSnapshot {
  id: TLShapeId
  x: number
  y: number
  attachedShapeIds: readonly TLShapeId[]
}

export interface ShapeSnapshot {
  id: TLShapeId
  type: TLShape["type"]
  x: number
  y: number
}

export type ShapeMove = ShapeSnapshot

// Module-level propagation guard. Lives outside React so it survives hook
// remounts and stays shared across any concurrent handler invocations inside
// a single editor batch.
let isPropagating = false

// Pure helper so we can unit-test the delta math without mounting tldraw.
// Returns the list of shape/pin moves triggered by `movedShapeId` shifting by
// (dx, dy). The moved shape itself is not included — the caller has already
// applied that move. Each affected shape (and pin) is emitted once, even when
// several pins' attached sets overlap.
export function computePinUpdates(
  pins: readonly PinSnapshot[],
  movedShapeId: TLShapeId,
  dx: number,
  dy: number,
  getShape: (id: TLShapeId) => ShapeSnapshot | null
): ShapeMove[] {
  const updates: ShapeMove[] = []
  const seen = new Set<TLShapeId>([movedShapeId])

  for (const pin of pins) {
    if (!pin.attachedShapeIds.includes(movedShapeId)) continue

    if (!seen.has(pin.id)) {
      seen.add(pin.id)
      updates.push({
        id: pin.id,
        type: "pin",
        x: pin.x + dx,
        y: pin.y + dy,
      })
    }

    for (const shapeId of pin.attachedShapeIds) {
      if (seen.has(shapeId)) continue
      const shape = getShape(shapeId)
      if (!shape) continue
      seen.add(shapeId)
      updates.push({
        id: shapeId,
        type: shape.type,
        x: shape.x + dx,
        y: shape.y + dy,
      })
    }
  }

  return updates
}

function snapshotPins(editor: Editor): PinSnapshot[] {
  const result: PinSnapshot[] = []
  for (const shape of editor.getCurrentPageShapes()) {
    if (shape.type !== "pin") continue
    const pin = shape as TLPinShape
    result.push({
      id: pin.id,
      x: pin.x,
      y: pin.y,
      attachedShapeIds: pin.props.attachedShapeIds,
    })
  }
  return result
}

export function usePinAttachment(editor: Editor | null) {
  useEffect(() => {
    if (!editor) return

    const disposeChange = editor.sideEffects.registerAfterChangeHandler(
      "shape",
      (prev, next) => {
        if (isPropagating) return
        if (next.type === "pin") return
        if (next.x === prev.x && next.y === prev.y) return

        const pins = snapshotPins(editor)
        if (pins.length === 0) return

        const dx = next.x - prev.x
        const dy = next.y - prev.y

        const updates = computePinUpdates(pins, next.id, dx, dy, (id) => {
          const shape = editor.getShape(id)
          if (!shape) return null
          return { id: shape.id, type: shape.type, x: shape.x, y: shape.y }
        })

        if (updates.length === 0) return

        isPropagating = true
        try {
          editor.run(() => {
            editor.updateShapes(
              updates.map((u) => ({
                id: u.id,
                type: u.type,
                x: u.x,
                y: u.y,
              }))
            )
          })
        } finally {
          isPropagating = false
        }
      }
    )

    const disposeDelete = editor.sideEffects.registerAfterDeleteHandler(
      "shape",
      (deleted: TLShape) => {
        if (deleted.type === "pin") return

        const pins = snapshotPins(editor).filter((pin) =>
          pin.attachedShapeIds.includes(deleted.id)
        )
        if (pins.length === 0) return

        editor.run(() => {
          const pinsToDelete: TLShapeId[] = []
          const pinsToUpdate: Array<{
            id: TLShapeId
            type: "pin"
            props: { attachedShapeIds: TLShapeId[] }
          }> = []

          for (const pin of pins) {
            const nextIds = pin.attachedShapeIds.filter(
              (id) => id !== deleted.id
            )
            if (nextIds.length < 2) {
              pinsToDelete.push(pin.id)
            } else {
              pinsToUpdate.push({
                id: pin.id,
                type: "pin",
                props: { attachedShapeIds: nextIds },
              })
            }
          }

          if (pinsToUpdate.length > 0) {
            editor.updateShapes(pinsToUpdate)
          }
          if (pinsToDelete.length > 0) {
            editor.deleteShapes(pinsToDelete)
          }
        })
      }
    )

    return () => {
      disposeChange()
      disposeDelete()
    }
  }, [editor])
}

